command:
let sprite, container;
let status = {
  "name": "Trägt Ball",
  "type": "specialability",
  "img": "systems/dsa5/icons/categories/ability_general.webp",
  "system": {
    "step": {
      "value": 1
    },
    "category": {
      "value": "fatePoints",
      "sub": 0
    },
    "effect": {
      "value": "-3 GS;"
    }
  }
};
if (!game.ball || !game.ball.container) {
  game.ball = {
    container: new PIXI.Container(),
    sprite: PIXI.Sprite.from("/worlds/der-adler-und-der-wal/assets/immanball.png")
  }
  sprite = game.ball.sprite;
  container = game.ball.container;
  sprite.anchor.set(0.5,0.5);
  container.addChild(sprite);
  game.ball.interval = setInterval(()=>{
  try { game.ball.sprite.rotation+=0.01;} catch (e) {clearInterval(game.ball.interval); game.ball = {};}
  },10);
}
sprite = game.ball.sprite;
container = game.ball.container;
if (game.ball.token) {
  game.ball.token.removeChild(container);
  if (game.ball.token.actor) {
    let hasItem = game.ball.token.actor.items.find(x => x.name===status.name&& x.type==="specialability");
    if (hasItem) {
      game.ball.token.actor.deleteEmbeddedDocuments("Item",[hasItem._id]);
    }
  }
}
let token = game.user.targets.first();
game.socket.emit('system.dsa5', {
    type: 'pixieContainer',
    pixi: {
      rotate: true,
      id: "immanBall",
      src: "/worlds/der-adler-und-der-wal/assets/immanball.png"
    },
    tokenId: token?token.id:false
});
if (!token) {
  return;
}
game.ball.token = token;
container.x = token.w/2;
container.y = token.h/2;
let scale = Math.max(token.document.width, token.document.height) * ((Math.abs(token.document.texture.scaleX) + Math.abs(token.document.texture.scaleY)) / 2);
sprite.width = canvas.dimensions.size * 1.4 * scale;
sprite.height = canvas.dimensions.size * 1.4 * scale;
token.addChildAt(container,0);
if (token.actor) {
  token.actor.createEmbeddedDocuments("Item",[status]);
}
